import {Component, OnInit} from '@angular/core';
import { faPencil, faTrash } from '@fortawesome/free-solid-svg-icons';
import {UserService} from "../user.service";
import {GENDERS} from "../user-form/user-form.component";
@Component({
  selector: 'app-user-list',
  templateUrl: './user-list.component.html',
  styleUrls: ['./user-list.component.scss']
})
export class UserListComponent implements OnInit {
  faPencil = faPencil;
  faTrash = faTrash;

  users: any[] = [];

  constructor(
    private userService: UserService
  ) {

  }

  async ngOnInit(): Promise<void> {
    await this.listUsers();
  }

  async listUsers(): Promise<void>{
    this.users = await this.userService.get<any[]>({
      url: "http://localhost:8080/api/users",
      //url: "https://1846-187-56-25-28.ngrok.io/api/users",
      params: {
      }
    });
  }

  getLabelGender(value: string): string | undefined {
    let gender = GENDERS.find((gender) => gender.value === value)
    return gender?.label;
  }

  async delete(id: number): Promise<void> {
    if (confirm("Deseja deletar este usuário?")) {
      await this.userService.delete<any>({
        url: `http://localhost:8080/api/users/${id}`,
        url: `https://1846-187-56-25-28.ngrok.io/api/users/${id}`,
        params: {}
      });
      await this.listUsers();
    }
  }

  onConfirm(value: any) {
    alert("Value:" + value);
  }
}
<div class="container">
  <div class="py-3 text-center">
    <h3>Cadastro de Usuários</h3>
  </div>
  <div class="row">
    <div class="col-12 d-flex align-content-end justify-content-end pb-5">
      <a class="btn btn-primary" [href]="'/user'">CADASTRAR USUÁRIO</a>
    </div>
  </div>
  <div class="row">
    <div class="col-md-12 mb-12">
      <table class="table">
        <thead>
        <tr>
          <th scope="col">#</th>
          <th scope="col">Nome</th>
          <th scope="col">Sobrenome</th>
          <th scope="col">Email</th>
          <th scope="col">Genero</th>
          <th scope="col">Ação</th>
        </tr>
        </thead>
        <tbody>
        <tr *ngFor="let user of users">
          <th scope="row">{{user.id}}</th>
          <td>{{user.firstName}}</td>
          <td>{{user.lastName}}</td>
          <td>{{user.email}}</td>
          <td>{{getLabelGender(user.gender)}}</td>
          <td>
            <a class="btn btn-outline-primary" [href]="'/user?id='+user.id">
              <fa-icon [icon]="faPencil"></fa-icon>
            </a>
            <button type="button" class="btn btn-outline-danger" data-toggle="confirmation" data-placement="right" (click)="delete(user.id)">
              <fa-icon [icon]="faTrash"></fa-icon>
            </button>
          </td>
        </tr>
        </tbody>
      </table>
    </div>
  </div>
</div>
